#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
//dp[N][N][N] --> 上一个数考虑到前i个区间，前面有k个数在第j个区间内的方案数
//typedef long long ll;
//#define int ll
const int N=510,Mod=1e9+7;int n,l[N],r[N],P[N<<1],p,dp[N<<1][N],inv[N],g[N<<1][N],s[N<<1];
inline int bnd(int x){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=x?l=m+1:r=m-1;return l-1;}
inline int qpow(int a,int b=Mod-2){int r(1);for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)r=1ll*r*a%Mod;return r;}
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
signed main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();rep(1,n,i)P[++p]=l[i]=read(),P[++p]=r[i]=read()+1;
	sort(P+1,P+p+1);p=unique(P+1,P+p+1)-P-1;rep(1,n,i)l[i]=bnd(l[i]),r[i]=bnd(r[i]);
	inv[0]=1;rep(1,n,i)inv[i]=qpow(i);
	rep(1,n,i)
	{
		memcpy(g,dp,sizeof(dp));memset(dp,0,sizeof(dp));
		rep(l[i],r[i]-1,j)dp[j][1]=P[j+1]-P[j];
		rep(1,p-1,j){s[j]=0;rep(1,i-1,k)DN(s[j]+=g[j][k]);DN(s[j]+=s[j-1]); }
		rep(1,p-1,j)
		{
			if(l[i]<=j&&j<r[i])dp[j][1]=(1ll*s[j-1]*(P[j+1]-P[j])+dp[j][1])%Mod;
			rep(1,i,k)
			{
				DN(dp[j][k]+=g[j][k]);
				if(k!=1&&l[i]<=j&&j<r[i])
				{
					dp[j][k]=(1ll*g[j][k-1]*(P[j+1]-P[j]-k+1)%Mod*inv[k]+dp[j][k])%Mod;
				} 
			}
		}
	}
	int ans=0;rep(1,p-1,j)rep(1,n,k)DN(ans+=dp[j][k]); 
	printf("%d\n",ans);
	
}
